const body = $input.first().json.body;

const required = ['patient_id', 'slot_id', 'chief_complaint'];

for (const field of required) {
  if (!body[field] || body[field].toString().trim() === '') {
    return [{
      json: {
        valid: false,
        error: `Missing required field: ${field}`
      }
    }];
  }
}

// Check for urgent keywords in symptoms
const urgentKeywords = [
  'chest pain', 'chest tightness', 'can\'t breathe',
  'difficulty breathing', 'unconscious', 'seizure',
  'stroke', 'severe bleeding', 'heart'
];

const symptoms = (body.pre_symptoms || '').toLowerCase();
const isUrgent = urgentKeywords.some(k => symptoms.includes(k));

return [{
  json: {
    valid: true,
    patient_id:      body.patient_id.trim(),
    slot_id:         body.slot_id.trim(),
    chief_complaint: body.chief_complaint.trim(),
    pre_symptoms:    body.pre_symptoms || null,
    urgent_flag:     isUrgent
  }
}];

