const body = $input.first().json.body;

if (!body.patient_id || !body.question) {
  return [{
    json: {
      valid: false,
      error: 'patient_id and question are required'
    }
  }];
}

return [{
  json: {
    valid: true,
    patient_id: body.patient_id.trim(),
    question:   body.question.trim()
  }
}];

const embedding = $input.first().json.data[0].embedding;
const patient_id = $('Extract Input').item.json.patient_id;
const question = $('Extract Input').item.json.question;

return [{
  json: {
    patient_id,
    question,
    embedding
  }
}];

const results = $input.all();
const question = $('Extract Input').item.json.question;

// Build context from matched notes
let context = '';
let sources = [];

results.forEach((item, index) => {
  const note = item.json;
  context += `Note ${index + 1} (similarity: ${(note.similarity * 100).toFixed(0)}%):\n${note.content}\n\n`;
  sources.push(`Note ${index + 1}: ${note.content.substring(0, 80)}...`);
});

if (!context) {
  context = 'No clinical notes found for this patient.';
}

const systemPrompt = `You are a clinical AI assistant helping a doctor 
review a patient's medical history. You answer questions based ONLY on 
the clinical notes provided. Be concise, accurate, and medically precise.
Always highlight any allergies or drug interactions if relevant.
If the information is not in the notes, say so clearly — do not guess.`;

const userPrompt = `Patient clinical notes:
${context}

Doctor's question: ${question}

Please provide a clear, concise answer based only on the notes above.
End your answer with a "Sources:" section listing which notes you used.`;

return [{
  json: {
    system_prompt: systemPrompt,
    user_prompt:   userPrompt,
    sources:       sources,
    question:      question,
    context_found: results.length > 0
  }
}];

const noteId = $('Loop Through Notes').item.json.id;
const embedding = $input.first().json.data[0].embedding;

return [{
  json: {
    id: noteId,
    embedding: JSON.stringify(embedding)
  }
}];

const answer = $input.first().json.output[0].content[0].text;
const question = $('Extract Input').item.json.question;
const contextFound = $('Build Prompt').item.json.context_found;

const responseBody = JSON.stringify({
  success:       true,
  question:      question,
  answer:        answer,
  context_found: contextFound,
  model:         'gpt-4o',
  timestamp:     new Date().toISOString()
});

return [{
  json: {
    responseBody
  }
}];

const body = $input.first().json.body;

const required = [
  'patient_id', 'appointment_id',
  'soap_subjective', 'soap_objective',
  'soap_assessment', 'soap_plan',
  'diagnosis', 'prescription', 'doctor_name'
];

for (const field of required) {
  if (!body[field] || body[field].toString().trim() === '') {
    return [{
      json: {
        valid: false,
        error: `Missing required field: ${field}`
      }
    }];
  }
}

// Combine all SOAP fields into one rich text for embedding
const combinedNote = `
Doctor: ${body.doctor_name}
Diagnosis: ${body.diagnosis}
Prescription: ${body.prescription}

Subjective: ${body.soap_subjective}
Objective: ${body.soap_objective}
Assessment: ${body.soap_assessment}
Plan: ${body.soap_plan}
${body.raw_notes ? 'Additional notes: ' + body.raw_notes : ''}
`.trim();

return [{
  json: {
    valid:            true,
    patient_id:       body.patient_id.trim(),
    appointment_id:   body.appointment_id.trim(),
    soap_subjective:  body.soap_subjective.trim(),
    soap_objective:   body.soap_objective.trim(),
    soap_assessment:  body.soap_assessment.trim(),
    soap_plan:        body.soap_plan.trim(),
    diagnosis:        body.diagnosis.trim(),
    prescription:     body.prescription.trim(),
    raw_notes:        body.raw_notes || null,
    doctor_name:      body.doctor_name.trim(),
    combined_note:    combinedNote
  }
}];

const visit = $('Insert Visit').item.json;
const note = $('Save Clinical Note').item.json;

const responseBody = JSON.stringify({
  success:    true,
  message:    'Consultation note saved and embedded into AI memory',
  visit_id:   visit.id,
  note_id:    note.id,
  timestamp:  new Date().toISOString()
});

return [{ json: { responseBody } }];

